<!DOCTYPE html><html lang="en"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Offer Workflow</title><script src="https://cdn.tailwindcss.com"></script><script src="https://unpkg.com/lucide@latest"></script></head>
<body class="bg-slate-50"><?php $id=$application['application_id']; $status=$application['application_status']; ?><div class="flex h-screen overflow-hidden"><?php include __DIR__ . '/../sidebar.php'; ?><div class="flex min-w-0 flex-1 flex-col"><?php include __DIR__ . '/../navbar.php'; ?><main class="flex-1 overflow-y-auto p-5 lg:p-7">
<a href="<?= base_url('Recruitment/offers') ?>" class="text-sm font-semibold text-slate-600">← Offers & Onboarding</a><div class="mt-4 flex flex-wrap items-start justify-between gap-3"><div><h1 class="text-2xl font-bold text-slate-900"><?= esc($application['candidate_name'] ?: $application['name']) ?></h1><p class="mt-1 text-sm text-slate-500"><?= esc($application['job_title']) ?> · <?= esc($application['department']) ?></p></div><span class="rounded-full bg-emerald-100 px-3 py-1 text-sm font-semibold text-emerald-800"><?= esc($status) ?></span></div>
<div class="mt-6 grid gap-5 xl:grid-cols-2">
<?php if ($canManage): ?><section class="rounded-xl border bg-white p-5 shadow-sm"><h2 class="font-bold">1. Salary package & document request</h2><form method="post" action="<?= base_url("Recruitment/offers/$id/request-documents") ?>" class="mt-4 space-y-3"><?= csrf_field() ?><input required type="number" min="1" step="0.01" name="offered_salary" value="<?= esc($application['offered_salary'] ?? '') ?>" placeholder="Annual salary" class="w-full rounded-lg border p-3"><input required type="date" name="proposed_joining_date" value="<?= esc($application['proposed_joining_date'] ?? '') ?>" class="w-full rounded-lg border p-3"><textarea name="salary_notes" placeholder="Package notes" class="w-full rounded-lg border p-3"><?= esc($application['salary_notes'] ?? '') ?></textarea><button class="rounded-lg bg-slate-900 px-4 py-2 font-semibold text-white">Save & request documents</button></form></section><?php endif; ?>
<section class="rounded-xl border bg-white p-5 shadow-sm"><h2 class="font-bold">2. Candidate documents</h2><p class="mt-2 text-sm text-slate-500">Status: <?= esc($application['verification_status'] ?: 'Not requested') ?></p><?php if (!$canManage && in_array($status,['Documents Requested','Documents Submitted'],true)): ?><form enctype="multipart/form-data" method="post" action="<?= base_url("Recruitment/offers/$id/upload-documents") ?>" class="mt-4 space-y-3"><?= csrf_field() ?><label class="block text-sm font-semibold">BGV / identity document<input type="file" name="bgv" accept=".pdf,.jpg,.jpeg,.png" class="mt-1 block w-full rounded-lg border p-2"></label><label class="block text-sm font-semibold">Experience document<input type="file" name="experience" accept=".pdf,.jpg,.jpeg,.png" class="mt-1 block w-full rounded-lg border p-2"></label><button class="rounded-lg bg-blue-600 px-4 py-2 font-semibold text-white">Submit documents</button></form><?php endif; ?><div class="mt-4 flex gap-3 text-sm"><?php if($application['bgv_document']): ?><a class="font-semibold text-blue-700" href="<?= base_url("Recruitment/offers/$id/document/bgv") ?>">BGV document</a><?php endif; ?><?php if($application['experience_document']): ?><a class="font-semibold text-blue-700" href="<?= base_url("Recruitment/offers/$id/document/experience") ?>">Experience document</a><?php endif; ?></div></section>
<?php if ($canManage): ?><section class="rounded-xl border bg-white p-5 shadow-sm"><h2 class="font-bold">3. Verification</h2><form method="post" action="<?= base_url("Recruitment/offers/$id/verify") ?>" class="mt-4 space-y-3"><?= csrf_field() ?><select name="verification_status" class="w-full rounded-lg border p-3"><option>Verified</option><option>Failed</option></select><textarea name="verification_notes" placeholder="Verification notes" class="w-full rounded-lg border p-3"><?= esc($application['verification_notes'] ?? '') ?></textarea><button class="rounded-lg bg-emerald-600 px-4 py-2 font-semibold text-white">Save verification</button></form></section>
<section class="rounded-xl border bg-white p-5 shadow-sm"><h2 class="font-bold">4. Issue offer</h2><div class="mt-3 rounded-lg bg-slate-50 p-4 text-sm"><div>Salary: <b><?= $application['offered_salary'] ? number_format((float)$application['offered_salary'],2) : '-' ?></b></div><div>Joining date: <b><?= esc($application['proposed_joining_date'] ?: '-') ?></b></div></div><?php if(in_array($application['offer_status'] ?? '', ['Sent','Accepted','Hired'],true)): ?><a target="_blank" href="<?= base_url("Recruitment/offers/$id/letter") ?>" class="mt-4 inline-block rounded-lg border border-violet-600 px-4 py-2 font-semibold text-violet-700">View / print offer letter</a><?php else: ?><form method="post" action="<?= base_url("Recruitment/offers/$id/send") ?>" class="mt-4"><?= csrf_field() ?><button class="rounded-lg bg-violet-600 px-4 py-2 font-semibold text-white">Digitally issue offer letter</button></form><?php endif; ?></section><?php endif; ?>
<?php if (!$canManage && in_array($application['offer_status'] ?? '', ['Sent','Accepted','Hired'],true)): ?><div class="xl:col-span-2"><a target="_blank" href="<?= base_url("Recruitment/offers/$id/letter") ?>" class="inline-block rounded-lg border border-violet-600 bg-white px-4 py-2 font-semibold text-violet-700">View / print complete offer letter</a></div><?php endif; ?>
<?php if (!$canManage && ($application['offer_status'] ?? '')==='Sent'): ?><section class="rounded-xl border-2 border-emerald-300 bg-white p-5 shadow-sm xl:col-span-2"><h2 class="font-bold">5. Review and digitally sign</h2><p class="mt-2 text-sm">I accept the offer for <b><?= esc($application['job_title']) ?></b>, with proposed joining date <b><?= esc($application['proposed_joining_date']) ?></b> and annual salary <b><?= number_format((float)$application['offered_salary'],2) ?></b>.</p><form method="post" action="<?= base_url("Recruitment/offers/$id/respond") ?>" class="mt-4 space-y-3"><?= csrf_field() ?><input name="signature_name" placeholder="Type your full legal name" class="w-full rounded-lg border p-3"><label class="flex gap-2 text-sm"><input type="checkbox" name="consent" value="1"> I agree that this typed name is my electronic signature.</label><textarea name="offer_decline_reason" placeholder="Reason if declining" class="w-full rounded-lg border p-3"></textarea><div class="flex gap-3"><button name="decision" value="accept" class="rounded-lg bg-emerald-600 px-4 py-2 font-semibold text-white">Accept & sign</button><button name="decision" value="decline" class="rounded-lg bg-red-600 px-4 py-2 font-semibold text-white">Decline offer</button></div></form></section><?php endif; ?>
<?php if ($canManage && ($application['offer_status'] ?? '')==='Accepted'): ?><section class="rounded-xl border-2 border-emerald-300 bg-white p-5 shadow-sm xl:col-span-2"><h2 class="font-bold">6. Hire & pre-onboard</h2><p class="mt-2 text-sm text-slate-600">Signed by <?= esc($application['signature_name']) ?>. Conversion updates the linked user into an active employee profile.</p><form method="post" action="<?= base_url("Recruitment/offers/$id/hire") ?>" class="mt-4 space-y-3"><?= csrf_field() ?><textarea name="onboarding_notes" class="w-full rounded-lg border p-3" placeholder="Pre-onboarding instructions or notes"></textarea><button class="rounded-lg bg-emerald-700 px-4 py-2 font-semibold text-white">Mark hired & convert to employee</button></form></section><?php endif; ?>
<?php if(($application['offer_status'] ?? '')==='Hired'): ?><section class="rounded-xl border-2 border-emerald-300 bg-emerald-50 p-5 xl:col-span-2"><h2 class="font-bold text-emerald-900">Pre-onboarding active</h2><p class="mt-2 text-sm text-emerald-800">Employee profile #<?= esc($application['employee_profile_id']) ?> · Joining <?= esc(date('d M Y',strtotime($application['proposed_joining_date']))) ?></p><?php if($application['onboarding_notes']): ?><p class="mt-3 whitespace-pre-line text-sm"><?= esc($application['onboarding_notes']) ?></p><?php endif; ?></section><?php endif; ?>
</div></main></div></div><?= view('partials/flash_toast',['toastSuccess'=>session()->getFlashdata('success'),'toastError'=>session()->getFlashdata('error')]) ?><script>lucide.createIcons()</script></body></html>
